  dokka(project(":gbfs-v3"))
  kover(project(":gbfs-v3"))

  dokka(project(":gofs-v1"))
  kover(project(":gofs-v1"))

  dokka(project(":gtfs-schedule"))
  kover(project(":gtfs-schedule"))
}

