package dev.sargunv.mobilitydata.gbfs.v3

import kotlinx.coroutines.test.runTest

class DocsSnippet {

  fun example() = runTest {
    // --8<-- [start:example]
    GbfsV3Client().use { gbfs -> // (1)!
      val service =
        gbfs
          .getServiceManifest( // (2)!
            discoveryUrl = "https://locomotion.app/api/gbfs/3.0/montreal/gbfs"
          )
